(()=>{const maxButton=document.getElementById('max-button');if(maxButton)maxButton.addEventListener('click',()=>{window.open(window.location.href,'_blank');})})();;(()=>{document.querySelectorAll('.nav-link').forEach(link=>{link.addEventListener('click',function(e){e.preventDefault();document.querySelectorAll('.nav-link').forEach(item=>{item.classList.remove('active');});this.classList.add('active');const targetId=this.getAttribute('href');if(targetId!=='#'){const targetElement=document.querySelector(targetId);if(targetElement){targetElement.scrollIntoView({behavior:'smooth',block:'start'});}}});});window.addEventListener('scroll',function(){const hexagrams=document.querySelectorAll('.card');let currentId='';hexagrams.forEach(hexagram=>{const rect=hexagram.getBoundingClientRect();if(rect.top<=100&&rect.bottom>=100){currentId=`#${hexagram.id}`;}});document.querySelectorAll('.nav-link').forEach(link=>{link.classList.remove('active');if(link.getAttribute('href')===currentId){link.classList.add('active');}});});})();;(()=>{const THEME_LIGHT='light';const THEME_DARK='dark';function setTheme(theme){const root=document.documentElement;root.classList.remove('light','dark');if(theme===THEME_DARK){root.classList.add('dark');}else{root.classList.add('light');}
root.style.transition='all 0.3s ease';setTimeout(()=>{root.style.transition='';},300);}
function getThemeFromURL(){const urlParams=new URLSearchParams(window.location.search);return urlParams.get('theme')||THEME_DARK;}
function setupMessageListener(){window.addEventListener('message',function(event){const data=event.data;if(data&&data.type==='THEME_CHANGE'){setTheme(data.theme);}else if(data&&data.type==='THEME_RESPONSE'){setTheme(data.theme);}});}
function requestCurrentTheme(){try{if(window.parent&&window.parent!==window){window.parent.postMessage({type:'THEME_REQUEST',timestamp:Date.now()},'*');}}catch(error){const theme=getThemeFromURL();setTheme(theme);}}
function setupThemeRequestHandler(){window.addEventListener('message',function(event){const data=event.data;if(data&&data.type==='THEME_REQUEST'){const currentTheme=document.documentElement.classList.contains('light')?THEME_LIGHT:THEME_DARK;const parentWindow=getParentWindowSource(event.source);if(!parentWindow){return;}
parentWindow.postMessage({type:'THEME_RESPONSE',theme:currentTheme,timestamp:Date.now()},event.origin);}});}
function getParentWindowSource(source){if(!source){return null;}
if(window.parent&&window.parent!==window&&source===window.parent){return window.parent;}
return null;}
function initTheme(){const savedTheme=localStorage.getItem('theme');const theme=savedTheme||getThemeFromURL();setTheme(theme);requestCurrentTheme();}
document.addEventListener('DOMContentLoaded',function(){initTheme();setupMessageListener();setupThemeRequestHandler();});})();;